    "startLine": 1,
    "totalLines": 544
  }
}

{
  "type": "text",
  "file": {
    "filePath": "/home/runner/workspace/app/theme.ts",
    "content": "import { Dimensions } from "react-native";

const { width } = Dimensions.get("window");

export const SPACING = {
  xs: 4,
  sm: 8,
  md: 12,
  lg: 16,
  xl: 20,
