    <KeyboardAvoidingView
      style={{ flex: 1, backgroundColor: AC.systemGroupedBackground }}
      behavior={Platform.OS === "ios" ? "padding" : undefined}
      keyboardVerticalOffset={80}
    >
      <Stack.Screen
        options={{
          headerTitle: () => {
            const dirName = thread.workDir
              ? thread.workDir.split("/").filter(Boolean).pop()
              : null;
            return (
              <View style={{ alignItems: "center" }}>
                <View style={{ flexDirection: "row", alignItems: "center", gap: 6 }}>
                  {threadStatus === "running" && (
                    <View style={{
                      width: 6,
                      height: 6,
                      borderRadius: 3,
                      backgroundColor: AC.systemBlue,
                    }} />
                  )}
                  <Text style={{ color: AC.label, fontSize: 15, fontWeight: "600" }} numberOfLines={1}>
                    {thread.title}
                  </Text>
                </View>
                {dirName ? (
                  <Text style={{ color: AC.systemGray, fontSize: 11, fontFamily: Platform.OS === "ios" ? "Menlo" : "monospace", marginTop: 1 }} numberOfLines={1}>
                    {dirName}
                  </Text>
                ) : null}
              </View>
            );
          },
          headerRight: () => headerRight,
        }}
      />
      <View
        style={{
          flex: 1,
          paddingBottom: bottom,
        }}
      >
        {/* Status indicator - slim inline pill */}
        {threadStatus === "running" && (
          <View
            style={{
              marginHorizontal: SPACING.lg,
              marginTop: SPACING.sm,
              flexDirection: "row",
              alignItems: "center",
              gap: 8,
              paddingHorizontal: SPACING.md,
              paddingVertical: SPACING.xs,
              backgroundColor: isDark ? "rgba(10,132,255,0.12)" : "rgba(10,132,255,0.08)",
              borderRadius: BORDER_RADIUS.full,
              alignSelf: "flex-start",
            }}
          >
            <ActivityIndicator size="small" color={AC.systemBlue} />
            <Text style={{ color: AC.systemBlue, fontSize: 12, fontWeight: "500" }}>
              Thinking…
            </Text>
          </View>
        )}

        {/* Messages */}
        <FlatList
          ref={listRef}
          data={messages}
          keyExtractor={(item) => item.id}
          contentContainerStyle={{
            padding: SPACING.lg,
            gap: SPACING.sm,
            flexGrow: 1,
          }}
          renderItem={({ item }) => <MessageBubble message={item} />}
          ListEmptyComponent={() => (
            <View
              style={{
                flex: 1,
                justifyContent: "center",
                alignItems: "center",
                gap: SPACING.sm,
                paddingVertical: 48,
              }}
            >
              <View style={{
                width: 48,
                height: 48,
                borderRadius: 24,
                backgroundColor: isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.04)",
                justifyContent: "center",
                alignItems: "center",
              }}>
                <IconSymbol
                  name="ellipsis.bubble"
                  color={AC.systemGray3}
                  size={22}
                />
              </View>
              <Text style={{ color: AC.systemGray, fontSize: 14 }}>
                Start a conversation
              </Text>
            </View>
          )}
        />

        {/* Slash command picker — floats above the input bar */}
        <SlashCommandPicker
          inputValue={input}
          visible={slashPickerVisible}
          onSelect={(cmd) => {
            setInput(cmd);
            setSlashPickerVisible(false);
          }}
        />

