        "-                }}",
        "-              >",
        "-                <IconSymbol",
        "-                  name="arrow.up"",
        "-                  size={14}",
        "-                  color={input.trim() ? (isDark ? "#000" : "#fff") : AC.systemGray3}",
        "-                />",
        "-              </View>",
        "-            </TouchableBounce>",
        "-          </View>",
        "-        </View>",
        "-      </View>",
        "-",
        "-      <BottomSheetModal",
        "-        ref={terminalRef}",
        "-        snapPoints={["40%", "70%"]}",
        "-        backgroundStyle={{",
        "-          backgroundColor: AC.systemBackground,",
        "-        }}",
        "-        handleIndicatorStyle={{ backgroundColor: AC.systemGray3 }}",
        "-      >",
        "-        <View style={{ flex: 1, padding: SPACING.md, gap: SPACING.md }}>",
        "-          <View style={{ flexDirection: "row", justifyContent: "space-between", alignItems: "center" }}>",
        "-            <Text style={{ color: AC.label, fontWeight: "600", fontSize: 15 }}>",
        "-              Terminal",
        "-            </Text>",
        "-            <TouchableBounce",
        "-              sensory",
        "-              onPress={() => terminalRef.current?.dismiss()}",
        "-            >",
        "-              <View style={{",
        "-                width: 28,",
        "-                height: 28,",
        "-                borderRadius: 14,",
        "-                backgroundColor: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.05)",",
        "-                justifyContent: "center",",
        "-                alignItems: "center",",
        "-              }}>",
        "-                <IconSymbol name="xmark" color={AC.systemGray} size={12} />",
        "-              </View>",
        "-            </TouchableBounce>",
        "-          </View>",
        "-          <View",
        "-            style={{",
        "-              flex: 1,",
        "-              backgroundColor: "#0a0a0a",",
        "-              borderRadius: BORDER_RADIUS.lg,",
        "-              padding: SPACING.md,",
        "-              gap: SPACING.xs,",
        "-            }}",
        "-          >",
        "-            <FlatList",
