          >
            <IconSymbol name="terminal" color={AC.label} size={14} />
          </View>
        </TouchableBounce>
        <TouchableBounce
          sensory
          disabled={!messages.length}
          onPress={copyConversation}
          style={{ opacity: messages.length ? 1 : 0.3 }}
        >
          <View
            style={{
              width: 32,
              height: 32,
              justifyContent: "center",
              alignItems: "center",
              backgroundColor: copiedConvo
