        "-          ListEmptyComponent={() => (",
        "-            <View",
        "-              style={{",
        "-                flex: 1,",
        "-                justifyContent: "center",",
        "-                alignItems: "center",",
        "-                gap: SPACING.sm,",
        "-                paddingVertical: 48,",
        "-              }}",
        "-            >",
        "-              <View style={{",
        "-                width: 48,",
        "-                height: 48,",
        "-                borderRadius: 24,",
        "-                backgroundColor: isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.04)",",
        "-                justifyContent: "center",",
        "-                alignItems: "center",",
