        "-              style={{",
        "-                opacity: !input.trim() || sending ? 0.3 : 1,",
        "-                marginBottom: SPACING.xs,",
        "-              }}",
        "-            >",
        "-              <View",
        "-                style={{",
        "-                  width: 32,",
        "-                  height: 32,",
        "-                  borderRadius: 16,",
        "-                  backgroundColor: input.trim() ? AC.label : (isDark ? "rgba(255,255,255,0.12)" : "rgba(0,0,0,0.08)"),",
