        "-              >",
        "-                <IconSymbol",
        "-                  name="arrow.up"",
        "-                  size={14}",
        "-                  color={input.trim() ? (isDark ? "#000" : "#fff") : AC.systemGray3}",
        "-                />",
        "-              </View>",
        "-            </TouchableBounce>",
        "-          </View>",
        "-        </View>",
