        "-              <View style={{",
        "-                width: 28,",
        "-                height: 28,",
        "-                borderRadius: 14,",
        "-                backgroundColor: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.05)",",
        "-                justifyContent: "center",",
        "-                alignItems: "center",",
        "-              }}>",
        "-                <IconSymbol name="xmark" color={AC.systemGray} size={12} />",
