        "+        >",
        "+          <IconSymbol name="checkmark" size={10} color={AC.systemGreen} />",
        "+          <Text style={{ fontSize: 11, color: AC.systemGreen }}>Copied</Text>",
        "+        </View>",
        "+      )}",
